#include <stdio.h>
#include <string.h>
#define MAXN 100005
int T, N, K, pi[MAXN], qi[MAXN];
char s[MAXN];
int dp[MAXN][MAXN];
int main() {
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &N, &K);
        for (int i = 0; i < N; i++) s[i] = '0';
        for (int i = 0; i < K; i++) {
            scanf("%d %d", &pi[i], &qi[i]);
            s[pi[i] - 1] = qi[i] + '0';
        }
        long long ans = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i; j < N; j++) {
                int flag = 1;
                for (int k = 0; k <= (j - i) / 2; k++) {
                    if (s[i + k] != s[j - k]) {
                        flag = 0;
                        break;
                    }
                }
                if (flag && (j - i) % 2 == 0) ans++;
            }
        }
        printf("%lld\n", ans);
    }
    return 0;
}

