import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int K = sc.nextInt();
            char[] s = new char[N];
            for (int i = 0; i < N; i++) s[i] = '0';
            for (int i = 0; i < K; i++) {
                int pi = sc.nextInt();
                int qi = sc.nextInt();
                s[pi - 1] = (char) (qi + '0');
            }
            long ans = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i; j < N; j++) {
                    int flag = 1;
                    for (int k = 0; k <= (j - i) / 2; k++) {
                        if (s[i + k] != s[j - k]) {
                            flag = 0;
                            break;
                        }
                    }
                    if (flag && (j - i) % 2 == 0) ans++;
                }
            }
            System.out.println(ans);
        }
    }
}

